protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing documents and raw SQL queries still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve "EntityType|Key" format so existing documents (e.g. "Product|123") remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed HasIndex — Cosmos DB provider now throws at startup.
    // Manage indexes via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

